def test_delete_employee_invalid_id_format():
    import requests
    token = <get_valid_hr_admin_token>
    headers = {'Authorization': f'Bearer {token}'}
    invalid_ids = ["'; DROP TABLE employees; --", "<script>alert('xss')</script>", "../../../etc/passwd"]
    for invalid_id in invalid_ids:
        resp = requests.delete(f'{BASE_URL}/api/employees/{invalid_id}', headers=headers)
        assert resp.status_code in [400, 404]
